import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2):
        return np.linalg.norm(pos1 - pos2) / truck_speed

    def average_distance_to_other_trucks(cur_truck_pos, all_truck_pos):
        distances = [np.linalg.norm(cur_truck_pos - pos) for pos in all_truck_pos if not np.array_equal(cur_truck_pos, pos)]
        if distances:
            return sum(distances) / len(distances)
        else:
            return 0

    best_node = None
    min_score = float('inf')

    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        if start_window > arrival_time:
            wait_time = start_window - arrival_time
        else:
            wait_time = 0

        if end_window < arrival_time:
            penalty = (arrival_time - end_window) ** 2  # Exponential penalty for missing time window
        else:
            penalty = 0

        avg_dist_other_trucks = average_distance_to_other_trucks(cur_truck_pos, all_truck_pos)

        # Adding a component that considers the average distance to other trucks to improve collective route efficiency
        score = (travel_time + 0.8 * wait_time + 1.5 * penalty) / (1 + 0.1 * avg_dist_other_trucks)

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node
